import React from "react";
import IssuerDashboard from "../components/issuer/IssuerDashboard";

export default function IssuerPortal() {
  return (
    <div className="page">
      <div className="page-header">
        <h1>Issuer Portal</h1>
        <span className="page-pill">For KYC providers</span>
      </div>
      <p className="page-subtitle">
        Banks, exchanges, and regulated providers approve or revoke
        reusable on‑chain KYC credentials for user wallets.
      </p>
      <div className="grid">
        <IssuerDashboard />
      </div>
    </div>
  );
}
